"""
Sales Analysis Engine using MongoDB Aggregation Pipelines

This module implements a robust SalesAnalyzer class for identifying top-performing
products within a specific date range, grouped by category.
"""

from datetime import datetime
from typing import Dict, List, Any
from pymongo import MongoClient
from pymongo.errors import ServerSelectionTimeoutError


class SalesAnalyzer:
    """
    A class to analyze sales data from MongoDB using aggregation pipelines.

    Attributes:
        db: MongoDB database instance
        client: MongoDB client connection
    """

    def __init__(self, db_url: str, db_name: str) -> None:
        """
        Initialize the SalesAnalyzer with MongoDB connection.

        Args:
            db_url: MongoDB connection URL
            db_name: Name of the database to connect to

        Raises:
            ServerSelectionTimeoutError: If unable to connect to MongoDB
        """
        try:
            self.client = MongoClient(db_url, serverSelectionTimeoutMS=5000)
            # Verify connection
            self.client.admin.command('ping')
            self.db = self.client[db_name]
        except ServerSelectionTimeoutError as e:
            raise ServerSelectionTimeoutError(f"Failed to connect to MongoDB at {db_url}: {e}")

    def get_top_performing_products(
        self,
        start_date: str,
        end_date: str,
        limit: int = 3
    ) -> Dict[str, List[Dict[str, Any]]]:
        """
        Retrieve top-performing products within a date range, grouped by category.

        Performance is measured by total revenue (price * quantity).

        Args:
            start_date: Start date in ISO 8601 format (inclusive)
            end_date: End date in ISO 8601 format (inclusive)
            limit: Number of top products to retrieve per category (default: 3)

        Returns:
            Dictionary where keys are category names and values are lists of
            product information sorted by revenue, quantity, and product ID.
            Each item contains: product_id, product_name, total_revenue, total_quantity

        Raises:
            ValueError: If date format is invalid
        """
        try:
            # Parse ISO 8601 dates
            start_datetime = datetime.fromisoformat(start_date.replace('Z', '+00:00'))
            end_datetime = datetime.fromisoformat(end_date.replace('Z', '+00:00'))
        except ValueError as e:
            raise ValueError(f"Invalid ISO 8601 date format: {e}")

        # Build the aggregation pipeline
        pipeline = [
            # Stage 1: Filter orders within the date range (inclusive)
            {
                "$match": {
                    "order_date": {
                        "$gte": start_datetime,
                        "$lte": end_datetime
                    }
                }
            },
            # Stage 2: Join with products collection to get category and price
            {
                "$lookup": {
                    "from": "products",
                    "localField": "product_id",
                    "foreignField": "product_id",
                    "as": "product_info"
                }
            },
            # Stage 3: Filter out orders with no matching product (orphaned orders)
            {
                "$match": {
                    "product_info": {
                        "$ne": []
                    }
                }
            },
            # Stage 4: Unwind product_info to access individual fields
            {
                "$unwind": "$product_info"
            },
            # Stage 5: Calculate revenue for each order and group by product
            {
                "$group": {
                    "_id": {
                        "product_id": "$product_id",
                        "product_name": "$product_info.product_name",
                        "category": "$product_info.category"
                    },
                    "total_revenue": {
                        "$sum": {
                            "$multiply": [
                                "$product_info.price",
                                "$quantity"
                            ]
                        }
                    },
                    "total_quantity": {
                        "$sum": "$quantity"
                    }
                }
            },
            # Stage 6: Reshape the document to separate category for grouping
            {
                "$project": {
                    "_id": 0,
                    "product_id": "$_id.product_id",
                    "product_name": "$_id.product_name",
                    "category": "$_id.category",
                    "total_revenue": {
                        "$round": [
                            "$total_revenue",
                            2
                        ]
                    },
                    "total_quantity": "$total_quantity"
                }
            },
            # Stage 7: Group by category and collect products
            {
                "$group": {
                    "_id": "$category",
                    "products": {
                        "$push": {
                            "product_id": "$product_id",
                            "product_name": "$product_name",
                            "total_revenue": "$total_revenue",
                            "total_quantity": "$total_quantity"
                        }
                    }
                }
            },
            # Stage 8: Sort products within each category and limit to top N
            {
                "$project": {
                    "_id": 0,
                    "category": "$_id",
                    "products": {
                        "$slice": [
                            {
                                "$sortArray": {
                                    "input": "$products",
                                    "sortBy": {
                                        "total_revenue": -1,
                                        "total_quantity": -1,
                                        "product_id": 1
                                    }
                                }
                            },
                            limit
                        ]
                    }
                }
            }
        ]

        # Execute the aggregation pipeline
        try:
            results = list(self.db.orders.aggregate(pipeline))
        except Exception as e:
            raise RuntimeError(f"Aggregation pipeline execution failed: {e}")

        # Format the output as a dictionary with category as key
        output: Dict[str, List[Dict[str, Any]]] = {}
        for result in results:
            category = result["category"]
            products = result["products"]
            output[category] = products

        return output

    def close(self) -> None:
        """Close the MongoDB connection."""
        if self.client:
            self.client.close()

